import React, { useState, useContext } from "react";
import { GeneralContext } from "./GeneralContext";
import "./BuyActionWindow.css";

const BuyActionWindow = ({ uid }) => {
  const [stockQuantity, setStockQuantity] = useState(1);
  const [stockPrice, setStockPrice] = useState(0.0);
  const { closeBuyWindow } = useContext(GeneralContext);

  const handleBuyClick = () => {
    // Logic for backend order placement will go here
    console.log(`Order placed for ${uid}: ${stockQuantity} @ ${stockPrice}`);
    closeBuyWindow();
  };

  return (
    <div className="container" id="buy-window">
      {/* Blue Header Section from your CSS */}
      <div className="header">
        <h3>
          Buy {uid} x {stockQuantity} Qty <span>@ Market</span>
        </h3>
        <div className="market-options">
          <label>
            <input type="radio" name="market" defaultChecked />
            BSE: ₹0.00
          </label>
          <label>
            <input type="radio" name="market" />
            NSE: ₹0.00
          </label>
        </div>
      </div>

      {/* Tabs Section */}
      <div className="tab">
        <button type="button">Regular</button>
        <button type="button">AMO</button>
        <button type="button">Iceberg</button>
      </div>

      {/* Inputs Section */}
      <div className="regular-order">
        <div className="inputs">
          <fieldset>
            <legend>Qty.</legend>
            <input
              type="number"
              name="qty"
              id="qty"
              onChange={(e) => setStockQuantity(Number(e.target.value))}
              value={stockQuantity}
            />
          </fieldset>
          <fieldset>
            <legend>Price</legend>
            <input
              type="number"
              name="price"
              id="price"
              step="0.05"
              onChange={(e) => setStockPrice(Number(e.target.value))}
              value={stockPrice}
            />
          </fieldset>
        </div>
      </div>

      {/* Footer Buttons Section */}
      <div className="buttons">
        <span>Margin required ₹0.00</span>
        <div>
          <button className="btn btn-blue" onClick={handleBuyClick}>
            Buy
          </button>
          <button className="btn btn-grey" onClick={() => closeBuyWindow()}>
            Cancel
          </button>
        </div>
      </div>
    </div>
  );
};

export default BuyActionWindow;
